const _fieldByKey: ReadonlyMap<string, PlantFilterFieldDef> = new Map(
  PLANT_FILTER_FIELDS.map((field) => [field.key, field] as const),
)

const _categoryByKey: ReadonlyMap<FilterCategory, PlantFilterCategory> = new Map(
  FILTER_CATEGORIES.map((category) => [category.key, category] as const),
)

const _dynamicFieldsByCategory: ReadonlyMap<FilterCategory, readonly PlantFilterFieldDef[]> = new Map(
  FILTER_CATEGORIES.map((category) => [
    category.key,
    PLANT_FILTER_FIELDS.filter((field) => field.category === category.key && field.uiPlacement === 'dynamic'),
  ] as const),
)

export function fieldDefForKey(fieldKey: string): PlantFilterFieldDef | undefined {
  return _fieldByKey.get(fieldKey)
}

export function dynamicFilterFieldsForCategory(category: FilterCategory): readonly PlantFilterFieldDef[] {
  return _dynamicFieldsByCategory.get(category) ?? []
}

export function categoryForField(fieldKey: string): PlantFilterCategory | undefined {
  const field = fieldDefForKey(fieldKey)
  return field ? _categoryByKey.get(field.category) : undefined
}

export function isStripField(fieldKey: string): boolean {
  return fieldDefForKey(fieldKey)?.uiPlacement === 'strip'
}

export function orderingForField(fieldKey: string): readonly string[] | undefined {
  const ordering = fieldDefForKey(fieldKey)?.ordering
  return ordering ? FILTER_VALUE_ORDERINGS[ordering] : undefined
}
